import React from 'react';
import { ReactComponent as StarNav } from '../Assets/Navbar/Star Navbar.svg';
import { ReactComponent as SeavaLogo } from '../Assets/Navbar/Logo Seavalanche Navbar.svg'
import { ReactComponent as KofiLogo } from '../Assets/Navbar/KofiNav.svg'
import { Link } from "react-router-dom";

function Navbar() {
    return (
        <div className='navbar'>
            <div className='page-border'>
                <div className='navbar-container'>
                    <Link to='/' className='SeavaLogo'><SeavaLogo /></Link>
                    <div className='navbar-menu'>
                        <div className='nbmenutext'><Link to='./Projects'>Projects</Link></div>
                        <StarNav className='StarNav'/>
                        <div className='nbmenutext'><Link to='./Commission'>Commission</Link></div>
                        <StarNav className='StarNav'/>
                        <div className='nbmenutext'><Link to='./About'>About</Link></div>
                    </div>
                    <a href='https://ko-fi.com/seavalanche' target="_blank" rel="noopener noreferrer" className='KofiLogo'><KofiLogo /></a>
                </div>
            </div>
        </div>
    )
}



export default Navbar;