import React from 'react';
import { ReactComponent as FooterSeava } from '../Assets/Footer/FooterSeavalancheLogo.svg'
import { ReactComponent as FooterStar } from '../Assets/Footer/FooterStar.svg'
import { ReactComponent as FooterOshyarena } from '../Assets/Footer/FooterOshyarenaLogo.svg'
import LowerPart from '../Assets/Footer/LowerPart.jpg'

function Footer() {
    return (
        <>
            <div className='LowerPart'>
                <img className='VesneaFooter' src={LowerPart} alt='S13 - Vesnea' />
                <div className='LowerText'>
                    <div>
                        <b>Project_next</b>
                        <br />
                        ( 2015 - 2019 )
                    </div>
                    <div>
                        <b>Project Rea</b>
                        <br />
                        ( 2020 - 2022 )
                    </div>
                    <div>
                        <b>Project Oshyarena</b>
                        <br />
                        ( 2021 - 2022 )
                    </div>
                    <div>
                        <b>Project Seava</b>
                        <br />
                        ( 2021 - 2022 )
                    </div>
                </div>
            </div>
            <div className='Footer'>
                <div className='FooterLogo'>
                    <a href='https://linktr.ee/seavalanche' target="_blank" rel="noopener noreferrer" ><FooterSeava className='FooterSeava' /></a>
                    <FooterStar className='FooterStar' />
                    <a href='https://linktr.ee/oshyarena' target="_blank" rel="noopener noreferrer"><FooterOshyarena className='FooterOshyarena' /></a>
                </div>
            </div>
        </>
    )
}

export default Footer;