import React from 'react';
import Project_next from '../Assets/Projects/Project_next.png'
import ProjectRea from '../Assets/Projects/Project Rea.png'
import ProjectOshyarena from '../Assets/Projects/Project Oshyarena.png'
import ProjectSeava from '../Assets/Projects/Project Seava.png'
import Showcase from '../Components/Showcase';
import Showcaseitem from '../Components/Showcaseitem';

function Projects() {
    return (
        <div className='Projects'>
            <div className='page-border'>
                <b>Projects are separate works that have their own main goals</b>
                <div className='Projectcard'>
                    <div className='ProjectitemL'>
                        <div className='Projectitemtitle'><h1>Project_next</h1><h2>(2015-2019)</h2></div>
                        <p>This is the early times of my digital art works. I learned to draw autodidactly with a Photoshop program and a mouse.
                            <br />Along the way, I learned to draw with more artstyles, learned more art theories that I can use in drawing, learned more artists on Twitter.
                        </p>
                    </div>
                    <img className='ProjectimgR' src={Project_next} alt='Project_next' />
                </div>
                <div className='Projectcard'>
                    <img className='ProjectimgL' src={ProjectRea} alt='Project Rea' />
                    <div className='ProjectitemR'>
                        <div className='Projectitemtitle'><h1>Project Rea</h1><h2>(2020-2022)</h2><br /></div>
                        <p>This project marks the time when I have obtained the necessary skills to actually try to speed up drawing process.<br />
                            As time goes on, the works should be better than before.
                        </p>
                    </div>
                </div>
                <div className='Projectcard'>
                    <div className='ProjectitemL'>
                        <div className='Projectitemtitle'><h1>Project Oshyarena</h1><h2>(2021-2022)</h2><br /></div>
                        <p>The purpose of this project is to draw freely without restrictions.<br /> Future plans is to draw related to photograph scenes, official merchandises, clothes, etc.
                        </p>
                    </div>
                    <img className='ProjectimgR' src={ProjectOshyarena} alt='Project Oshyarena' />
                </div>
                <div className='Projectcard'>
                    <img className='ProjectimgL' src={ProjectSeava} alt='Project Seava' />
                    <div className='ProjectitemR'>
                        <div className='Projectitemtitle'><h1>Project Seava</h1><h2>(2021-2022)</h2><br /></div>
                        <p>Any original characters will be drawn under Project Seava. Commissions is one of this project’s objective. Promotional works will be done under this project. In fact, this website project falls under Project Seava!
                        </p>
                    </div>
                </div>
                <div className='Showcase'>
                    <b>Total Artworks</b>
                    <Showcase>
                        <Showcaseitem title='Project_next' number='51*' />
                        <Showcaseitem title='Project Rea' number='>550' />
                        <Showcaseitem title='Project Oshyarena' number='>120' />
                        <Showcaseitem title='Project Seava' number='>50' />
                        <Showcaseitem title='Total Time Spent' number='>35000 mins' />
                    </Showcase>
                </div>
            </div>
        </div>
    )
}

export default Projects;