import React from 'react';

function Commissionitem(props) {
    return (
        <div className='Commissionitem'>
            <div className='comitemimgcon'>
                <img className='comitemimg' src={props.img1} alt={props.alt1} />
                <img className='comitemimg' src={props.img2} alt={props.alt2} />
                <img className='comitemimg' src={props.img3} alt={props.alt3} />
            </div>
            <div className='comitemtext'>
                {props.title}
            </div>
        </div>
    )
}

export default Commissionitem;