import React from 'react';

function Mainpageitem(props) {
    return (
        <div className='Mainpageitem'>
            <img className='itemimg' src={props.image} alt={props.desc} />
            <div className='itemtext'>
                {props.title} <br />
                <b>{props.desc}</b>
            </div>
        </div>
    )
}

export default Mainpageitem;